#!/usr/bin/env node
/**
 * Sprint 6.4a — compute SHA-256 of src/db/schema.ts and write the digest
 * to src/lib/portability/schema-hash.generated.ts.
 *
 * Invoked via the `prebuild` npm hook so every production build refreshes
 * the hash automatically. The hash is the version gate for the data
 * portability export/import flow: an export emitted by one schema cannot
 * be imported into a container running a different schema.
 *
 * Idempotent — re-running with no schema change leaves the generated file
 * unchanged (so it never trips the file-watcher in dev).
 */

import { createHash } from 'node:crypto';
import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'node:fs';
import { dirname, join } from 'node:path';

const ROOT = process.cwd();
const SCHEMA_PATH = join(ROOT, 'src', 'db', 'schema.ts');
const OUT_PATH = join(ROOT, 'src', 'lib', 'portability', 'schema-hash.generated.ts');

const schemaText = readFileSync(SCHEMA_PATH, 'utf8');
const digest = createHash('sha256').update(schemaText).digest('hex');
const hash = `sha256:${digest}`;

const body =
  `// AUTO-GENERATED by scripts/compute-schema-hash.mjs — DO NOT EDIT BY HAND.\n` +
  `// Regenerated on every \`npm run build\` via the prebuild hook.\n` +
  `// Source: src/db/schema.ts (sha256 of file contents).\n` +
  `export const SCHEMA_HASH = '${hash}';\n`;

mkdirSync(dirname(OUT_PATH), { recursive: true });

let existing = '';
if (existsSync(OUT_PATH)) {
  existing = readFileSync(OUT_PATH, 'utf8');
}
if (existing !== body) {
  writeFileSync(OUT_PATH, body, 'utf8');
  console.log(`[schema-hash] wrote ${hash} → ${OUT_PATH}`);
} else {
  console.log(`[schema-hash] unchanged (${hash})`);
}
